from fastapi import APIRouter, Depends, HTTPExceptionfrom sqlalchemy.orm import Sessionfrom database import get_dbfrom models import Item, LibraryImagefrom pydantic import BaseModelfrom typing import Optionalimport uuidrouter = APIRouter()# --- Schemas ---class ItemCreate(BaseModel):    library_image_id: str    position: int    price_amount: Optional[str] = None    price_unit: Optional[str] = None    price_prefix: Optional[str] = None    description_en: Optional[str] = None    description_zh: Optional[str] = None    notes: Optional[str] = Noneclass ItemUpdate(BaseModel):    position: Optional[int] = None    price_amount: Optional[str] = None    price_unit: Optional[str] = None    price_prefix: Optional[str] = None    description_en: Optional[str] = None    description_zh: Optional[str] = None    notes: Optional[str] = None    image_offset_x: Optional[int] = None    image_offset_y: Optional[int] = None    cell_render_url: Optional[str] = None    image_scale: Optional[float] = None# --- Endpoints ---@router.get("/project/{project_id}")def get_items(project_id: str, db: Session = Depends(get_db)):    items = db.query(Item).filter(        Item.project_id == project_id    ).order_by(Item.position).all()    result = []    for item in items:        result.append({            "id": item.id,            "project_id": item.project_id,            "library_image_id": item.library_image_id,            "position": item.position,            "price_amount": item.price_amount,            "price_unit": item.price_unit,            "price_prefix": item.price_prefix,            "description_en": item.description_en,            "description_zh": item.description_zh,            "notes": item.notes,            "image_offset_x": item.image_offset_x,            "image_offset_y": item.image_offset_y,            "cell_render_url": item.cell_render_url,            "image_scale": item.image_scale,            "image": {                "url": item.image.url,                "name": item.image.name            } if item.image else None        })    return result@router.post("/project/{project_id}")def create_item(project_id: str, data: ItemCreate, db: Session = Depends(get_db)):    # verify image exists in library    image = db.query(LibraryImage).filter(        LibraryImage.id == data.library_image_id    ).first()    if not image:        raise HTTPException(status_code=404, detail="Library image not found")    item = Item(        id=str(uuid.uuid4()),        project_id=project_id,        **data.model_dump()    )    db.add(item)    db.commit()    db.refresh(item)    return item@router.get("/{item_id}")def get_item(item_id: str, db: Session = Depends(get_db)):    item = db.query(Item).filter(Item.id == item_id).first()    if not item:        raise HTTPException(status_code=404, detail="Item not found")    return item@router.patch("/{item_id}")def update_item(item_id: str, data: ItemUpdate, db: Session = Depends(get_db)):    item = db.query(Item).filter(Item.id == item_id).first()    if not item:        raise HTTPException(status_code=404, detail="Item not found")    for field, value in data.model_dump(exclude_none=True).items():        setattr(item, field, value)    item.cell_render_url = None  # mark as stale    db.commit()    db.refresh(item)    return item@router.delete("/{item_id}")def delete_item(item_id: str, db: Session = Depends(get_db)):    item = db.query(Item).filter(Item.id == item_id).first()    if not item:        raise HTTPException(status_code=404, detail="Item not found")    db.delete(item)    db.commit()    return {"ok": True}